{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { margin: 0; size: A4; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 9pt; color: #1a1a2e; background: #fff; }
  .page { max-width: 820px; margin: 0 auto; padding: 0; }

  /* HEADER */
  .hotel-logo { max-height: 52px; max-width: 95px; }
  .logo-box {
    display: inline-block; width: 46px; height: 46px;
    background: #1a1a2e; color: #fff; font-size: 16pt; font-weight: 700;
    text-align: center; line-height: 46px; border-radius: 5px;
  }
  .hotel-name { font-size: 14pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7.5pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 14px 0 16px; }

  /* STATUS PILL */
  .pill {
    display: inline-block; padding: 2px 9px; border-radius: 10px;
    font-size: 7pt; font-weight: 700; text-transform: uppercase;
    letter-spacing: 0.4px; margin-right: 5px;
    border: 1px solid #d1d5db; background: #f9fafb; color: #374151;
  }
  .pills-row { margin-bottom: 14px; }

  /* SECTION TITLE */
  .section-title { font-size: 7.5pt; font-weight: 700; color: #1a1a2e; text-transform: uppercase; letter-spacing: 0.6px; background: #f1f3f8; border-left: 3px solid #1a1a2e; border-bottom: 1px solid #d1d5db; padding: 5px 9px; margin-top: 14px; margin-bottom: 8px; }

  /* INFO TABLE */
  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .info-table td {
    padding: 4px 8px; font-size: 9pt;
    border-bottom: 1px solid #f1f5f9;
    vertical-align: middle; white-space: nowrap;
  }
  .info-table tr:last-child td { border-bottom: none; }
  .info-key { width: 22%; color: #1a1a2e; font-weight: 700; }
  .info-val { width: 28%; color: #1a1a2e; font-weight: 400; }

  /* INVOICE / PAYMENT TABLE */
  .data-table { width: 100%; border-collapse: collapse; font-size: 8.5pt; margin-bottom: 4px; }
  .data-table thead tr { background: #f1f3f8; color: #1a1a2e; border-bottom: 2px solid #1a1a2e; }
  .data-table thead th { padding: 6px 9px; text-align: left; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.4px; }
  .data-table thead th.num { text-align: right; }
  .data-table tbody tr:nth-child(even) { background: #f9fafb; }
  .data-table tbody td { padding: 7px 9px; border-bottom: 1px solid #f1f5f9; color: #374151; }
  .data-table tbody td.num { text-align: right; }
  .data-table tfoot tr { border-top: 2px solid #1a1a2e; }
  .data-table tfoot td { padding: 7px 9px; font-weight: 700; color: #1a1a2e; background: #f9fafb; }
  .data-table tfoot td.num { text-align: right; }

  /* BALANCE BOX */
  .balance-table { width: 55%; margin-left: 45%; border-collapse: collapse; margin-bottom: 4px; }
  .balance-table td { padding: 6px 10px; font-size: 9pt; border-bottom: 1px solid #f1f5f9; }
  .b-label { color: #6b7280; }
  .b-value { text-align: right; font-weight: 600; color: #1a1a2e; }
  .total-row td { background: #f1f3f8; color: #1a1a2e; font-weight: 700; font-size: 9.5pt; border-top: 2px solid #1a1a2e; border-bottom: 1px solid #d1d5db; }
  .credit-row td { background: #f9fafb; color: #15803d; font-weight: 600; border: none; font-size: 8pt; }
  .due-row td { background: #f9fafb; color: #dc2626; font-weight: 600; border: none; font-size: 8pt; }

  /* FOOTER */
  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 20px 0 12px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 16px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}
                <img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}
                <div class="logo-box">{{ (company or 'H')[:1] }}</div>
              {% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">Guest Folio</div>
        <div class="doc-subtitle">Check-In Summary &amp; Charges</div>
        <div class="doc-ref">
          <strong>Folio:</strong> {{ checkin.name }}<br>
          <strong>Generated:</strong> {{ generated_at }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- STATUS PILLS -->
  <div class="pills-row">
    {% set st = (checkin.status or '') | lower %}
    {% if st == 'checked in' %}<span class="pill">&#9679; Checked In</span>
    {% elif st == 'checked out' %}<span class="pill">&#10003; Checked Out</span>
    {% else %}<span class="pill">{{ checkin.status }}</span>{% endif %}
    {% if checkin.room_number %}<span class="pill">Room {{ checkin.room_number }}</span>{% endif %}
    {% if checkin.room_type %}<span class="pill">{{ checkin.room_type }}</span>{% endif %}
  </div>

  <!-- STAY DETAILS -->
  <div class="section-title">Stay Details</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:22%" /><col style="width:28%" />
      <col style="width:22%" /><col style="width:28%" />
    </colgroup>
    <tr>
      <td class="info-key">Check-In</td>
      <td class="info-val">{{ checkin.check_in_datetime }}</td>
      <td class="info-key">Expected Check-Out</td>
      <td class="info-val">{{ checkin.expected_check_out_datetime }}</td>
    </tr>
    <tr>
      <td class="info-key">Number of Nights</td>
      <td class="info-val">{{ checkin.number_of_nights }} night{% if checkin.number_of_nights != 1 %}s{% endif %}</td>
      <td class="info-key">Rate per Night</td>
      <td class="info-val">&#x20a6;{{ "{:,.0f}".format(checkin.rate_amount | float) }}</td>
    </tr>
    <tr>
      <td class="info-key">Room</td>
      <td class="info-val">{{ checkin.room_number or '&mdash;' }}</td>
      <td class="info-key">Room Type</td>
      <td class="info-val">{{ checkin.room_type or '&mdash;' }}</td>
    </tr>
    {% if checkin.reservation %}
    <tr>
      <td class="info-key">Reservation</td>
      <td class="info-val" colspan="3">{{ checkin.reservation }}</td>
    </tr>
    {% endif %}
  </table>

  <!-- GUEST INFORMATION -->
  <div class="section-title">Guest Information</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:22%" /><col style="width:28%" />
      <col style="width:22%" /><col style="width:28%" />
    </colgroup>
    <tr>
      <td class="info-key">Guest Name</td>
      <td class="info-val">{{ checkin.guest or '&mdash;' }}</td>
      <td class="info-key">Contact Number</td>
      <td class="info-val">{{ checkin.contact_number or '&mdash;' }}</td>
    </tr>
    {% if checkin.id_type %}
    <tr>
      <td class="info-key">ID Type</td>
      <td class="info-val">{{ checkin.id_type }}</td>
      <td class="info-key">Source</td>
      <td class="info-val">{{ checkin.reservation_source or '&mdash;' }}</td>
    </tr>
    {% endif %}
  </table>

  <!-- INVOICE LEDGER -->
  <div class="section-title">Invoice Ledger</div>
  {% if invoices %}
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th>#</th>
        <th>Invoice</th>
        <th>Type</th>
        <th>Date</th>
        <th class="num">Amount</th>
        <th class="num">Outstanding</th>
      </tr>
    </thead>
    <tbody>
      {% for inv in invoices %}
      <tr>
        <td style="color:#9ca3af;">{{ loop.index }}</td>
        <td style="font-weight:600;">{{ inv.invoice }}</td>
        <td style="color:#6b7280;">{{ inv.invoice_type or 'Sales Invoice' }}</td>
        <td style="color:#6b7280;">{{ inv.posting_date }}</td>
        <td class="num">{% if inv.is_return %}&minus; {% endif %}&#x20a6;{{ "{:,.0f}".format((inv.amount or 0) | float | abs) }}</td>
        <td class="num" style="{% if inv.outstanding_amount | float > 0 %}color:#dc2626;font-weight:600;{% elif inv.outstanding_amount | float < 0 %}color:#15803d;{% endif %}">
          &#x20a6;{{ "{:,.0f}".format((inv.outstanding_amount or 0) | float | abs) }}
        </td>
      </tr>
      {% endfor %}
    </tbody>
    <tfoot>
      <tr>
        <td colspan="4">Total Charges</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(total_charges | float) }}</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(total_outstanding | float) }}</td>
      </tr>
    </tfoot>
  </table>
  {% else %}
  <p style="padding:12px;color:#9ca3af;font-size:8pt;border:1px dashed #e5e7eb;">No invoices on this folio.</p>
  {% endif %}

  <!-- ACQUIRED BILLS / TRANSFER HISTORY -->
  {% if checkin.acquired_bills %}
  <div class="section-title">Acquired Bills (Transferred In)</div>
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th>#</th>
        <th>Transfer Ref</th>
        <th>From Guest</th>
        <th>Source Invoice</th>
        <th>Date</th>
        <th>Status</th>
        <th class="num">Amount</th>
        <th class="num">Outstanding</th>
      </tr>
    </thead>
    <tbody>
      {% for bill in checkin.acquired_bills %}
      <tr>
        <td style="color:#9ca3af;">{{ loop.index }}</td>
        <td style="font-weight:600;">{{ bill.name }}</td>
        <td style="color:#6b7280;">{{ bill.from_guest or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ bill.source_invoice or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ bill.transfer_date[:10] if bill.transfer_date else '&mdash;' }}</td>
        <td>
          {% if bill.status == 'Approved' %}
            <span style="color:#15803d;font-weight:600;">Approved</span>
          {% elif bill.status == 'Pending' %}
            <span style="color:#d97706;font-weight:600;">Pending</span>
          {% else %}
            {{ bill.status }}
          {% endif %}
        </td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format((bill.total_amount or 0) | float) }}</td>
        <td class="num" style="{% if (bill.outstanding_amount or 0) | float > 0 %}color:#dc2626;font-weight:600;{% endif %}">
          &#x20a6;{{ "{:,.0f}".format((bill.outstanding_amount or 0) | float) }}
        </td>
      </tr>
      {% endfor %}
    </tbody>
  </table>
  {% endif %}

  <!-- PAYMENTS -->
  <div class="section-title">Payments Received</div>
  {% if payments %}
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th>#</th>
        <th>Payment</th>
        <th>Mode</th>
        <th>Date</th>
        <th class="num">Amount</th>
      </tr>
    </thead>
    <tbody>
      {% for pmt in payments %}
      {% if pmt.docstatus == 1 %}
      <tr>
        <td style="color:#9ca3af;">{{ loop.index }}</td>
        <td style="font-weight:600;">{{ pmt.payment_id }}</td>
        <td style="color:#6b7280;">{{ pmt.mode_of_payment or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ pmt.posting_date }}</td>
        <td class="num" style="color:#15803d;font-weight:600;">&#x20a6;{{ "{:,.0f}".format((pmt.paid_amount or 0) | float) }}</td>
      </tr>
      {% endif %}
      {% endfor %}
    </tbody>
    <tfoot>
      <tr>
        <td colspan="4">Total Paid</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(total_paid | float) }}</td>
      </tr>
    </tfoot>
  </table>
  {% else %}
  <p style="padding:12px;color:#9ca3af;font-size:8pt;border:1px dashed #e5e7eb;">No payments recorded.</p>
  {% endif %}

  <!-- BALANCE SUMMARY -->
  <div class="section-title">Billing Summary</div>
  <table class="balance-table" cellpadding="0" cellspacing="0">
    <tr>
      <td class="b-label">Gross Charges</td>
      <td class="b-value">&#x20a6;{{ "{:,.2f}".format((checkin.billing_summary.gross_charges or total_charges) | float) }}</td>
    </tr>
    <tr>
      <td class="b-label">Net Bill</td>
      <td class="b-value">&#x20a6;{{ "{:,.2f}".format((checkin.billing_summary.net_bill or checkin.billing_summary.gross_charges or total_charges) | float) }}</td>
    </tr>
    <tr>
      <td class="b-label">Total Received</td>
      <td class="b-value">&#x20a6;{{ "{:,.2f}".format((checkin.billing_summary.total_received or total_paid) | float) }}</td>
    </tr>
    <tr class="total-row">
      <td>Outstanding</td>
      <td style="text-align:right;">
        {% set outstanding = (checkin.billing_summary.balance_amount or checkin.total_outstanding_amount or balance) | float %}
        {% if outstanding < 0 %}&minus; {% endif %}&#x20a6;{{ "{:,.2f}".format(outstanding | abs) }}
      </td>
    </tr>
    <tr class="credit-row">
      <td>Payment Status</td>
      <td style="text-align:right;">
        {% set outstanding = (checkin.billing_summary.balance_amount or checkin.total_outstanding_amount or balance) | float %}
        {% if outstanding < 0 %}Credit Balance
        {% elif outstanding == 0 %}Settled in Full
        {% else %}Balance Due{% endif %}
      </td>
    </tr>
  </table>

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This folio is generated by the {{ company }} Property Management System.<br>
          For queries please contact the front desk with your folio reference.<br>
          <strong style="color:#374151;">Folio Reference: {{ checkin.name }}</strong>
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>

</div>
</body>
</html>"}
